            var connection = context.Database.GetDbConnection();
            connection.Open();

            // INSERT Categories
            using (var transaction = connection.BeginTransaction())
            {
                using var cmd = connection.CreateCommand();
                cmd.Transaction = transaction;
                cmd.CommandText = "SET IDENTITY_INSERT Categories ON";
                cmd.ExecuteNonQuery();

                context.Database.UseTransaction(transaction);
                context.Categories.AddRange(categories);
                context.SaveChanges();

                cmd.CommandText = "SET IDENTITY_INSERT Categories OFF";
                cmd.ExecuteNonQuery();
                transaction.Commit();
            }

            // INSERT Books
            using (var transaction = connection.BeginTransaction())
            {
                using var cmd = connection.CreateCommand();
                cmd.Transaction = transaction;
                cmd.CommandText = "SET IDENTITY_INSERT Books ON";
                cmd.ExecuteNonQuery();

                context.Database.UseTransaction(transaction);
                context.Books.AddRange(books);
                context.SaveChanges();

                cmd.CommandText = "SET IDENTITY_INSERT Books OFF";
                cmd.ExecuteNonQuery();
                transaction.Commit();
            }

            // INSERT Comics
            using (var transaction = connection.BeginTransaction())
            {
                using var cmd = connection.CreateCommand();
                cmd.Transaction = transaction;
                cmd.CommandText = "SET IDENTITY_INSERT Comics ON";
                cmd.ExecuteNonQuery();

                context.Database.UseTransaction(transaction);
